import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const randInt = (a,b) => Math.floor(Math.random()*(b-a+1))+a;
const pick = a => a[Math.floor(Math.random()*a.length)];

function genSentences(text, dur) {
  const lines = text.split('\n').filter(l=>l.trim());
  let t=0; const avg=dur/lines.length;
  return lines.map(l=>{const d=Math.max(1,avg+(Math.random()-.5)*avg*.6);const s={start_time:+(t).toFixed(1),end_time:+(t+d).toFixed(1),text:l.trim()};t+=d;return s;});
}

// 对话模板数据 [title, transcript, transcript_cn, questions]
const D = [
["Campus Tour","A: Welcome to our campus tour! I'm Sarah.\nB: Hi Sarah! I'm Tom, excited to see the campus.\nA: Let's start with the library—over two million volumes.\nB: Impressive! Digital resources too?\nA: Absolutely, hundreds of academic databases.\nB: Study spaces?\nA: Quiet floors, group rooms, and a cafe.\nB: Perfect. Next stop?\nA: The student center with restaurants, shops, and 300+ organizations.\nB: Can't wait to explore!","A: 欢迎参加校园参观！我是莎拉。\nB: 你好莎拉！我是汤姆，很期待。\nA: 从图书馆开始——超过两百万册。\nB: 有数字资源吗？\nA: 当然，数百个学术数据库。\nB: 学习空间？\nA: 安静楼层、小组室和咖啡馆。\nB: 完美。下一站？\nA: 学生中心，有餐厅、商店和300+组织。\nB: 迫不及待！",[{q:"What's the main purpose?",a:"Job interview",b:"Campus tour",c:"Library orientation",d:"Club meeting",ans:"B",exp:"Sarah带领Tom参观校园。"},{q:"How many volumes in the library?",a:"1 million",b:"Over 2 million",c:"3 million",d:"500,000",ans:"B",exp:"图书馆有超过两百万册。"},{q:"What's at the student center?",a:"Only a cafe",b:"Classrooms",c:"Restaurants, shops, and 300+ organizations",d:"Sports facilities",ans:"C",exp:"学生中心有餐厅、商店和300+组织。"}]],
["Library Book Return","A: I'd like to return these books.\nB: Student ID please. You have a $5 fine for a book returned 3 days late.\nA: Can I pay now?\nB: Yes. We also waive fines if you volunteer 2 hours here.\nA: Great option! When can I volunteer?\nB: This Saturday 9-11 AM.\nA: I'll sign up. Thanks!\nB: You can also renew online up to twice.","A: 我想还书。\nB: 请出示学生证。有一本书逾期3天，罚款5美元。\nA: 现在能付吗？\nB: 可以。做2小时志愿者可减免罚款。\nA: 好选择！什么时候？\nB: 本周六9-11点。\nA: 我报名。谢谢！\nB: 也可以网上续借最多两次。",[{q:"How much is the fine?",a:"$3",b:"$5",c:"$10",d:"$15",ans:"B",exp:"罚款5美元。"},{q:"How to waive the fine?",a:"Pay double",b:"Write a review",c:"Volunteer 2 hours",d:"Donate books",ans:"C",exp:"做2小时志愿者可减免。"},{q:"How many online renewals?",a:"1",b:"2",c:"3",d:"Unlimited",ans:"B",exp:"网上续借最多两次。"}]],
["Dormitory Move-in","A: Moving into Room 302 today.\nB: Welcome to Green Hall! Need your housing contract and ID.\nA: Here they are. When do I get my key?\nB: After paperwork. You'll also get a key card.\nA: Dorm rules?\nB: Quiet hours 10PM-7AM weekdays. No cooking in rooms, shared kitchens on each floor.\nA: Visitors?\nB: Until 10PM. Overnight guests registered 24 hours in advance.\nA: Mail?\nB: Lobby mailbox, number matches your room.","A: 今天搬进302房间。\nB: 欢迎来到格林楼！需要合同和身份证。\nA: 这是。什么时候拿钥匙？\nB: 办完文件后。还有门禁卡。\nA: 宿舍规定？\nB: 工作日安静时间晚10到早7。房间禁止烹饪，每层有共享厨房。\nA: 访客？\nB: 到晚10点。过夜客人提前24小时登记。\nA: 邮件？\nB: 大厅邮箱，号码对应房间。",[{q:"What room?",a:"201",b:"302",c:"103",d:"420",ans:"B",exp:"搬进302房间。"},{q:"Quiet hours on weekdays?",a:"9PM-6AM",b:"10PM-7AM",c:"11PM-8AM",d:"10PM-6AM",ans:"B",exp:"安静时间晚10到早7。"},{q:"Overnight guest requirement?",a:"Pay extra",b:"Inform roommate",c:"Register 24 hours ahead",d:"Advisor permission",ans:"C",exp:"过夜客人提前24小时登记。"}]],
["Course Registration","A: Professor, I can't register for your advanced psychology course.\nB: What's wrong, Lisa?\nA: System says I need permission, but I took the prerequisite.\nB: You took Psych 201, but this needs Psych 202 too.\nA: Any way to still take it?\nB: Students with strong records can take it concurrently. Your GPA is 3.7.\nA: What do I need?\nB: Override form with my signature, and attend the first two weeks.\nA: I'll get the form today. Thank you!","A: 教授，我注册不了高级心理学。\nB: 怎么了丽莎？\nA: 系统说要许可，但我修了先修课。\nB: 你修了心理学201，但这门还需要202。\nA: 还有办法吗？\nB: 成绩优秀的可以同时修。你GPA 3.7。\nA: 我要做什么？\nB: 填超员申请表让我签字，并参加前两周。\nA: 我今天就去领表。谢谢！",[{q:"Why can't Lisa register?",a:"Course full",b:"Needs Psych 202",c:"Low GPA",d:"No permission",ans:"B",exp:"需要心理学202。"},{q:"What's Lisa's GPA?",a:"3.2",b:"3.5",c:"3.7",d:"3.9",ans:"C",exp:"GPA是3.7。"},{q:"What must Lisa do?",a:"Wait next semester",b:"Take Psych 202 first",c:"Override form and attend 2 weeks",d:"Write a petition",ans:"C",exp:"填超员申请表并参加前两周。"}]],
["Meal Plan","A: I'd like a meal plan. What's available?\nB: Basic: 10 meals/week. Standard: 14. Premium: unlimited.\nA: Prices?\nB: Basic $1500/semester, Standard $2000, Premium $2500.\nA: Standard works. Can I change later?\nB: Within first 2 weeks each semester.\nA: Does it cover the cafe?\nB: Standard and Premium include dining dollars. Standard has $100/semester.\nA: I'll go with Standard.","A: 我想办餐饮计划。有什么？\nB: 基本10餐/周，标准14，高级无限。\nA: 价格？\nB: 基本1500/学期，标准2000，高级2500。\nA: 标准适合。可以改吗？\nB: 每学期前两周内。\nA: 含咖啡馆吗？\nB: 标准和高级含餐饮额度。标准100/学期。\nA: 我选标准。",[{q:"How many meals in Standard?",a:"10",b:"14",c:"20",d:"Unlimited",ans:"B",exp:"标准每周14餐。"},{q:"When can you change plans?",a:"Any time",b:"First 2 weeks",c:"Before semester",d:"Mid-semester",ans:"B",exp:"每学期前两周内。"},{q:"Dining dollars in Standard?",a:"50",b:"75",c:"100",d:"200",ans:"C",exp:"标准每学期100餐饮额度。"}]],
["Part-time Job","A: Is the research assistant position still available?\nB: Yes. Graduate or undergraduate?\nA: Junior in biology. Lab experience since sophomore year.\nB: Great. It involves data collection for our marine biology project.\nA: Hours per week?\nB: About 15. Flexible, but Wednesday afternoon lab meetings required.\nA: Pay?\nB: $14/hour for undergrads, $18 for grads.\nA: How to apply?\nB: Resume and statement of interest by next Friday.","A: 研究助理还有吗？\nB: 有。研究生还是本科生？\nA: 生物大三。大二起有实验经验。\nB: 好。涉及海洋生物学数据收集。\nA: 每周几小时？\nB: 约15。灵活，但周三下午要开会。\nA: 薪资？\nB: 本科14美元/时，研究生18。\nA: 怎么申请？\nB: 下周五前交简历和兴趣说明。",[{q:"Student's major?",a:"Chemistry",b:"Marine biology",c:"Biology",d:"Environmental science",ans:"C",exp:"生物专业。"},{q:"When are lab meetings?",a:"Monday AM",b:"Wednesday PM",c:"Friday AM",d:"Thursday PM",ans:"B",exp:"周三下午。"},{q:"Pay for undergrads?",a:"$12/hr",b:"$14/hr",c:"$16/hr",d:"$18/hr",ans:"B",exp:"本科生14美元/时。"}]],
["Gym Membership","A: I'd like a gym membership.\nB: Student ID? All enrolled students get free basic membership.\nA: What's included?\nB: Weight room, pool, and indoor track during regular hours.\nA: Fitness classes?\nB: Premium membership, $50/semester.\nA: Pool reservations?\nB: No reservation for lap swimming. Diving area needs 1-day advance signup.\nA: I'll start with basic.","A: 我想办健身会员。\nB: 学生证？所有在校生免费基本会员。\nA: 包含什么？\nB: 健身房、泳池和室内跑道。\nA: 健身课？\nB: 高级会员50美元/学期。\nA: 泳池要预约吗？\nB: 泳道不需要。跳水区提前一天。\nA: 先办基本的。",[{q:"Basic membership includes?",a:"Weights, pool, classes",b:"Weights, pool, track",c:"Pool, track, classes",d:"All facilities",ans:"B",exp:"健身房、泳池和室内跑道。"},{q:"Premium cost?",a:"$30",b:"$40",c:"$50",d:"$60",ans:"C",exp:"50美元/学期。"},{q:"What needs advance signup?",a:"Lap swimming",b:"Weight room",c:"Indoor track",d:"Diving area",ans:"D",exp:"跳水区需提前报名。"}]],
["Roommate Conflict","A: Mike, can we talk? You playing music late bothers me.\nB: Sorry! I'll use headphones after 11 from now on.\nA: Thanks. Can we agree on a cleaning schedule?\nB: Take turns every other week?\nA: Works. Also, whoever notices trash is full takes it out.\nB: Reasonable. Glad we talked.\nA: Communication is key.\nB: Absolutely. Let's address things right away.","A: 迈克，能谈谈吗？你晚上放音乐困扰我。\nB: 对不起！11点后我戴耳机。\nA: 谢谢。能定打扫时间表吗？\nB: 轮流隔周怎么样？\nA: 可以。谁看到垃圾满了谁倒。\nB: 合理。很高兴我们谈了。\nA: 沟通很重要。\nB: 绝对，有问题立刻说。",[{q:"First problem raised?",a:"Room messy",b:"Late-night music",c:"Trash full",d:"Too many guests",ans:"B",exp:"晚上放音乐影响睡眠。"},{q:"Cleaning schedule?",a:"Clean together weekly",b:"Take turns every other week",c:"Hire service",d:"Each cleans own area",ans:"B",exp:"轮流隔周打扫。"},{q:"Trash rule?",a:"Every Monday",b:"Whoever notices it's full",c:"Alternate days",d:"Person with more trash",ans:"B",exp:"谁看到满了谁倒。"}]],
["Scholarship","A: I'd like to apply for the Dean's Scholarship.\nB: GPA 3.5+ and leadership in extracurriculars required.\nA: My GPA is 3.8, I'm debate club president.\nB: Promising. Need transcript, personal statement, and 2 recommendation letters.\nA: Deadline?\nB: March 15th. Reviews in April, results by May 1st.\nA: How much?\nB: Full tuition for one year, about $20,000.\nA: Incredible! I'll apply.\nB: Start your statement early—it carries weight.","A: 我想申请院长奖学金。\nB: 需要GPA 3.5+和课外领导力。\nA: 我GPA 3.8，辩论社社长。\nB: 有希望。需要成绩单、个人陈述和2封推荐信。\nA: 截止日期？\nB: 3月15日。4月审核，5月1日前公布。\nA: 金额？\nB: 一学年全额学费，约2万美元。\nA: 太棒了！我一定申请。\nB: 尽早开始写陈述。",[{q:"GPA required?",a:"3.0+",b:"3.3+",c:"3.5+",d:"3.8+",ans:"C",exp:"需要3.5以上。"},{q:"Deadline?",a:"Feb 28",b:"Mar 15",c:"Apr 1",d:"May 1",ans:"B",exp:"3月15日。"},{q:"Scholarship covers?",a:"Half tuition",b:"Room & board",c:"Full tuition one year",d:"All expenses",ans:"C",exp:"一学年全额学费。"}]],
["Study Abroad","A: Tell me about the Japan exchange program.\nB: Partnerships with 3 universities in Tokyo/Osaka. One semester, transferable credits.\nA: Need Japanese?\nB: Recommended but not required. Many courses in English.\nA: Cost?\nB: Pay regular tuition here. Extra for airfare, housing, living—about $5000/semester.\nA: Study abroad scholarships?\nB: Grants from $1000-$3000 based on need and merit.","A: 介绍日本交流项目。\nB: 与东京/大阪3所大学合作。一学期，学分可转。\nA: 需要日语吗？\nB: 推荐但非必须。很多课英语授课。\nA: 费用？\nB: 付本校学费。额外约5000美元/学期。\nA: 有奖学金吗？\nB: 根据需求和成绩1000-3000美元。",[{q:"How long is the program?",a:"1 month",b:"1 semester",c:"1 year",d:"2 years",ans:"B",exp:"一学期。"},{q:"Extra cost per semester?",a:"$3000",b:"$5000",c:"$7000",d:"$10000",ans:"B",exp:"约5000美元。"},{q:"What determines grants?",a:"Only merit",b:"Only need",c:"Need and merit",d:"Destination",ans:"C",exp:"根据需求和成绩。"}]],
["Computer Lab","A: I can't connect to campus Wi-Fi.\nB: Student network? You need to install the security certificate first.\nA: Download page won't load.\nB: Use a lab computer to download it to USB. Science building lab has the most computers.\nA: Is there a printer?\nB: Yes, on every floor. 10 cents/page black and white. Use student ID to release jobs.","A: 我连不上校园Wi-Fi。\nB: 学生网络？需要先安装安全证书。\nA: 下载页打不开。\nB: 用实验室电脑下载到U盘。科学楼电脑最多。\nA: 有打印机吗？\nB: 有，每层都有。黑白10美分/页。用学生证打印。",[{q:"Why can't connect?",a:"Wi-Fi down",b:"Need security certificate",c:"Old laptop",d:"Wrong password",ans:"B",exp:"需要安装安全证书。"},{q:"Where to download?",a:"App store",b:"IT services page",c:"Email",d:"USB from IT",ans:"B",exp:"从IT服务页面下载。"},{q:"Print cost?",a:"5 cents",b:"10 cents",c:"15 cents",d:"20 cents",ans:"B",exp:"黑白10美分/页。"}]],
["Club Fair","A: So many clubs here! Any photography club?\nB: Yes! Meets Saturday mornings, $30/semester including equipment.\nA: What about the volunteer club?\nB: Community Service Club does food drives and tutoring. Meets every other Wednesday evening.\nA: Can I sign up for both?\nB: Fill out these forms and you'll get event emails.","A: 好多社团！有摄影吗？\nB: 有！周六上午，30美元/学期含设备。\nA: 志愿者社团呢？\nB: 社区服务社做食物捐赠和辅导。隔周周三晚上。\nA: 两个都能报名吗？\nB: 填这些表格就行。",[{q:"When does photo club meet?",a:"Friday PM",b:"Saturday AM",c:"Sunday PM",d:"Wednesday PM",ans:"B",exp:"周六上午。"},{q:"Photo club fee?",a:"$20",b:"$30",c:"$40",d:"$50",ans:"B",exp:"30美元/学期。"},{q:"Volunteer club meets when?",a:"Every Wednesday",b:"Every other Wednesday",c:"Every Saturday",d:"Every Sunday",ans:"B",exp:"隔周周三晚上。"}]],
["Shuttle Schedule","A: When's the next north campus shuttle?\nB: Every 20 minutes on weekdays. Next in 5 minutes.\nA: How long the ride?\nB: Usually 15 minutes, up to 25 in rush hour.\nA: Does it make stops?\nB: 3 stops: student center, engineering, sports complex.\nA: Weekend schedule?\nB: Every 40 minutes. Last shuttle 8PM weekends, 11PM weekdays.","A: 下一班北校区班车？\nB: 工作日每20分钟。下一班5分钟后。\nA: 车程？\nB: 通常15分钟，高峰最多25。\nA: 有停靠吗？\nB: 3站：学生中心、工程楼、体育中心。\nA: 周末？\nB: 每40分钟。末班周末8点，工作日11点。",[{q:"Weekday frequency?",a:"Every 10 min",b:"Every 15 min",c:"Every 20 min",d:"Every 30 min",ans:"C",exp:"工作日每20分钟。"},{q:"How many stops?",a:"2",b:"3",c:"4",d:"5",ans:"B",exp:"3站。"},{q:"Last weekday shuttle?",a:"8 PM",b:"9 PM",c:"10 PM",d:"11 PM",ans:"D",exp:"工作日末班11点。"}]],
["Health Center","A: I'd like a health center appointment.\nB: Symptoms?\nA: Sore throat and low fever for 2 days.\nB: Opening at 2:30 PM today.\nA: What to bring?\nB: Student ID and insurance card. First visit, arrive 15 min early for forms.\nA: Co-pay?\nB: No co-pay with university insurance. Others depend on coverage.","A: 我想预约健康中心。\nB: 症状？\nA: 嗓子疼低烧2天。\nB: 今天下午2:30有空位。\nA: 要带什么？\nB: 学生证和保险卡。首次提前15分钟到填表。\nA: 有自付费吗？\nB: 大学保险无自付。其他看保险范围。",[{q:"Student's symptoms?",a:"Headache",b:"Sore throat and low fever",c:"Stomachache",d:"Back pain",ans:"B",exp:"嗓子疼低烧2天。"},{q:"When is appointment?",a:"10 AM",b:"2:30 PM",c:"Tomorrow 9 AM",d:"Tomorrow 3 PM",ans:"B",exp:"下午2:30。"},{q:"No co-pay for whom?",a:"Any insured",b:"University insurance holders",c:"All students",d:"Grad students",ans:"B",exp:"大学保险无自付。"}]],
["Lost and Found","A: I lost my backpack yesterday. Anyone turn it in?\nB: Describe it?\nA: Navy blue North Face with Stanford logo.\nB: No North Face, but a dark blue one from the library.\nA: Laptop compartment inside?\nB: Yes, and water bottle with initials J.W.\nA: That's mine! I'm Jessica Williams.\nB: Need your student ID to verify.","A: 昨天丢了背包。有人交来吗？\nB: 描述一下？\nA: 深蓝色北面，有斯坦福标志。\nB: 没北面，但有图书馆交来的深蓝色包。\nA: 有笔记本隔层？\nB: 有，还有水瓶写着J.W。\nA: 那是我的！我是Jessica Williams。\nB: 需要学生证核实。",[{q:"Backpack color?",a:"Black",b:"Navy blue",c:"Red",d:"Green",ans:"B",exp:"深蓝色。"},{q:"Where was it found?",a:"Cafeteria",b:"Gym",c:"Library",d:"Student center",ans:"C",exp:"图书馆交来的。"},{q:"Initials on bottle?",a:"M.S.",b:"A.K.",c:"J.W.",d:"R.T.",ans:"C",exp:"写着J.W。"}]],
["Parking Permit","A: I'd like a parking permit.\nB: Resident or commuter?\nA: Commuter, live 20 minutes away.\nB: Lot C, $300/year. Residents pay $400 for Lot D.\nA: Where's Lot C?\nB: South side near engineering. Shuttle every 10 min at peak.\nA: What to apply?\nB: License, registration, and insurance proof. Online or in person.\nA: Processing time?\nB: 3-5 business days.","A: 我想申请停车许可。\nB: 住校还是走读？\nA: 走读，住20分钟远。\nB: C区300美元/年。住校D区400。\nA: C区在哪？\nB: 南侧近工程楼。高峰每10分钟班车。\nA: 申请要什么？\nB: 驾照、登记和保险证明。在线或亲自。\nA: 处理多久？\nB: 3-5工作日。",[{q:"Lot C cost?",a:"$200",b:"$300",c:"$400",d:"$500",ans:"B",exp:"300美元/年。"},{q:"Lot C location?",a:"North",b:"East",c:"South",d:"West",ans:"C",exp:"校园南侧。"},{q:"Processing time?",a:"1-2 days",b:"3-5 days",c:"5-7 days",d:"1-2 weeks",ans:"B",exp:"3-5工作日。"}]],
["Academic Advising","A: Professor Davis, I want to discuss next semester's courses.\nB: Let me check your record, Sarah. What courses?\nA: Advanced Statistics, Social Psychology, and a Spanish elective.\nB: Stats is challenging. Prerequisite done?\nA: Yes, Intro to Stats last semester, A minus.\nB: Social Psych is popular—register early. What about your capstone?\nA: Cognitive behavioral therapy research. Would you advise me?\nB: Excellent topic! Happy to help.","A: 戴维斯教授，想讨论下学期课程。\nB: 查查你的记录，莎拉。什么课？\nA: 高级统计、社会心理和西班牙语选修。\nB: 统计有挑战。先修完了？\nA: 上学期统计学导论，A-。\nB: 社会心理热门——早注册。毕业项目呢？\nA: 认知行为疗法研究。您指导吗？\nB: 优秀课题！乐意帮忙。",[{q:"Sarah's Stats grade?",a:"A",b:"A minus",c:"B plus",d:"B",ans:"B",exp:"统计学导论A-。"},{q:"Capstone topic?",a:"Social psych",b:"Stats methods",c:"Cognitive behavioral therapy",d:"Spanish",ans:"C",exp:"认知行为疗法。"},{q:"Advice about Social Psych?",a:"Take next year",b:"Register early",c:"Different elective",d:"Take online",ans:"B",exp:"尽早注册。"}]],
["Counseling Center","A: I'd like a counseling appointment.\nB: First visit?\nA: Yes. Overwhelmed with coursework, trouble sleeping.\nB: Opening Thursday 3 PM with Dr. Martinez.\nA: What to expect?\nB: Intake assessment, about 50 minutes. Completely confidential.\nA: Fee?\nB: First 6 sessions free. Then $15/session.","A: 我想预约咨询。\nB: 第一次？\nA: 是。课业压力大，睡眠困难。\nB: 周四3点有Dr. Martinez。\nA: 怎样？\nB: 入校评估，约50分钟。完全保密。\nA: 收费？\nB: 前6次免费。之后15美元/次。",[{q:"Why visiting?",a:"Academic advising",b:"Overwhelmed and sleep trouble",c:"Relationships",d:"Career",ans:"B",exp:"课业压力大，睡眠困难。"},{q:"First session length?",a:"30 min",b:"40 min",c:"50 min",d:"60 min",ans:"C",exp:"约50分钟。"},{q:"Free sessions?",a:"3",b:"4",c:"5",d:"6",ans:"D",exp:"前6次免费。"}]],
["International Orientation","A: Welcome! I'm Maria, international student coordinator.\nB: I'm Kenji from Japan. Visa questions?\nA: F-1 students must maintain 12+ credit hours per semester.\nB: Can I work?\nA: On campus up to 20 hours/week. Off-campus needs CPT/OPT.\nB: Winter break travel?\nA: Get I-20 travel signature 2 weeks before departure.\nB: International student association?\nA: Yes! Cultural events and monthly meetings.","A: 欢迎！我是Maria，国际学生协调员。\nB: 我是日本的Kenji。签证问题？\nA: F-1学生每学期至少12学分。\nB: 可以工作吗？\nA: 校内最多20小时/周。校外需CPT/OPT。\nB: 寒假旅行？\nA: 出发前2周获I-20旅行签名。\nB: 有国际学生协会吗？\nA: 有！文化活动和月会。",[{q:"Minimum credit hours?",a:"9",b:"10",c:"12",d:"15",ans:"C",exp:"每学期至少12学分。"},{q:"Max on-campus work?",a:"10 hrs",b:"15 hrs",c:"20 hrs",d:"25 hrs",ans:"C",exp:"最多20小时/周。"},{q:"Travel signature timing?",a:"1 week before",b:"2 weeks before",c:"1 month before",d:"Day of travel",ans:"B",exp:"出发前2周。"}]],
["Graduation Check","A: Am I on track for graduation?\nB: Business Admin with Marketing minor, right?\nA: Yes.\nB: All major requirements done. Minor still needs Marketing Strategy.\nA: Registered for that. General education?\nB: Still need diversity requirement. Cultural Anthropology has openings.\nA: Total credits?\nB: Need 120. You have 111, so current courses should cover it.","A: 我毕业进度如何？\nB: 工商管理，市场营销辅修？\nA: 是的。\nB: 主修完成。辅修还差营销战略。\nA: 已注册。通识教育？\nB: 还差多元化要求。文化人类学有名额。\nA: 总学分？\nB: 需要120。你有111，加这学期的课够了。",[{q:"Minor still needs?",a:"Marketing Strategy",b:"Consumer Behavior",c:"Digital Marketing",d:"Brand Management",ans:"A",exp:"还差营销战略。"},{q:"Unfulfilled requirement?",a:"Writing",b:"Science",c:"Diversity",d:"Language",ans:"C",exp:"还差多元化要求。"},{q:"Current credits?",a:"105",b:"108",c:"111",d:"115",ans:"C",exp:"111学分。"}]],
["Financial Aid Appeal","A: I need a financial aid appeal. My father lost his job.\nB: You can submit a special circumstances appeal with documentation.\nA: I have the documents. How long?\nB: 2-4 weeks. Committee reviews every Friday.\nA: Emergency help while waiting?\nB: Emergency fund up to $1000 for immediate hardship.","A: 我要经济援助申诉。父亲失业了。\nB: 可以提交特殊情况申诉，需要文件。\nA: 我有。要多久？\nB: 2-4周。每周五审核。\nA: 等待期间有紧急帮助吗？\nB: 紧急基金最多1000美元。",[{q:"Why appealing?",a:"Grades improved",b:"Income reduced from job loss",c:"Transferring",d:"Won scholarship",ans:"B",exp:"父亲失业收入减少。"},{q:"Appeal timeline?",a:"1-2 weeks",b:"2-4 weeks",c:"4-6 weeks",d:"6-8 weeks",ans:"B",exp:"2-4周。"},{q:"Emergency fund max?",a:"$500",b:"$1000",c:"$2000",d:"$3000",ans:"B",exp:"最多1000美元。"}]],
["Tutoring Center","A: I'm struggling with calculus. Tutoring center help?\nB: Yes! Free peer tutors for math. Online scheduling, 45-min sessions.\nA: Do they help with homework?\nB: They guide problem-solving, not just give answers.\nA: I understand lectures but can't apply concepts.\nB: Very common. Also try study groups for your section.","A: 微积分很吃力。辅导中心帮忙吗？\nB: 是！免费数学辅导员。在线预约，45分钟。\nA: 帮做作业吗？\nB: 引导解题方法，不只给答案。\nA: 我懂课堂但不会应用。\nB: 很常见。也试试学习小组。",[{q:"Session length?",a:"30 min",b:"45 min",c:"60 min",d:"90 min",ans:"B",exp:"45分钟。"},{q:"Tutor approach?",a:"Give answers",b:"Do homework",c:"Guide problem-solving",d:"Lecture",ans:"C",exp:"引导解题方法。"},{q:"What else recommended?",a:"Private tutor",b:"Study groups",c:"Online videos",d:"More textbooks",ans:"B",exp:"也试试学习小组。"}]],
["Career Fair","A: Tips for the career fair next week?\nB: Research companies first. About 50 are coming.\nA: I've seen the list.\nB: Narrow to 5-6. Prepare a 30-second elevator pitch.\nA: What to include?\nB: Major, experience, position you want. Bring 15 copies of resume.\nA: Anything else?\nB: Portfolio with pen. Send thank-you emails within 48 hours.","A: 下周招聘会有建议吗？\nB: 先研究公司。约50家参加。\nA: 已看名单。\nB: 缩到5-6家。准备30秒自我介绍。\nA: 包含什么？\nB: 专业、经验和找的职位。带15份简历。\nA: 还要什么？\nB: 带笔的文件夹。48小时内发感谢邮件。",[{q:"How many companies?",a:"About 30",b:"About 40",c:"About 50",d:"About 60",ans:"C",exp:"约50家。"},{q:"Pitch length?",a:"15 seconds",b:"30 seconds",c:"1 minute",d:"2 minutes",ans:"B",exp:"30秒。"},{q:"When to send thank-yous?",a:"24 hours",b:"48 hours",c:"1 week",d:"2 weeks",ans:"B",exp:"48小时内。"}]],
["Exam Conflict","A: Professor, my economics and biology finals are at the same time.\nB: Policy says higher enrollment course takes priority.\nA: Which has more students?\nB: Biology has ~200, my class ~80. Take biology as scheduled, I'll offer you an alternate.\nA: When?\nB: Tuesday 2 PM. Same format, different questions.","A: 教授，经济学和生物期末同一时间。\nB: 政策说注册多的课优先。\nA: 哪门人多？\nB: 生物约200人，我的课约80人。按计划考生物，我给你安排替代。\nA: 什么时候？\nB: 周二下午2点。格式同，题目不同。",[{q:"Student's problem?",a:"Missed registration",b:"Two exams same time",c:"Wrong format",d:"Need study time",ans:"B",exp:"两门考试时间冲突。"},{q:"Which takes priority?",a:"Major course",b:"Earlier date",c:"Higher enrollment",d:"First scheduled",ans:"C",exp:"注册多的优先。"},{q:"Alternate exam when?",a:"Monday PM",b:"Tuesday AM",c:"Tuesday 2 PM",d:"Wednesday AM",ans:"C",exp:"周二下午2点。"}]],
["Event Planning","A: Our Environmental Club wants a campus clean-up.\nB: Submit proposal 3 weeks before. Include date, time, location, participants, resources needed.\nA: Will they provide trash bags and gloves?\nB: Yes, facilities can supply those. Consider refreshments for volunteers too.\nA: Registration table?\nB: Reserve in student center, up to 3 days. Include in proposal.","A: 环保社想办校园清洁。\nB: 提前3周提交提案。包含日期、时间、地点、人数和所需资源。\nA: 提供垃圾袋和手套吗？\nB: 会的，后勤可以提供。考虑志愿者茶点。\nA: 报名台？\nB: 学生中心预约，最多3天。写入提案。",[{q:"How far in advance?",a:"1 week",b:"2 weeks",c:"3 weeks",d:"1 month",ans:"C",exp:"提前3周。"},{q:"What will facilities provide?",a:"Refreshments",b:"Trash bags and gloves",c:"T-shirts",d:"Sound equipment",ans:"B",exp:"垃圾袋和手套。"},{q:"Table reservation limit?",a:"1 day",b:"2 days",c:"3 days",d:"5 days",ans:"C",exp:"最多3天。"}]],
["Changing Schedule","A: I need to drop my T-Th history and add MWF section.\nB: MWF has 12 seats available.\nA: Add-drop deadline?\nB: This Friday 5 PM. After that, special permission needed.\nA: Financial aid affected?\nB: As long as you maintain 12 credits full-time. You have 15 now.\nA: Process it now?\nB: Confirmation email within the hour.","A: 我要退周二周四的历史课加周一三五的。\nB: MWF有12个名额。\nA: 加退课截止？\nB: 本周五5点。之后需特别许可。\nA: 影响经济援助吗？\nB: 保持12学分全日制就行。你目前15学分。\nA: 现在办？\nB: 一小时内确认邮件。",[{q:"Add-drop deadline?",a:"Wednesday",b:"Thursday",c:"Friday 5 PM",d:"Next Monday",ans:"C",exp:"本周五5点。"},{q:"Current credits?",a:"12",b:"13",c:"14",d:"15",ans:"D",exp:"15学分。"},{q:"When confirmed?",a:"Immediately",b:"Within an hour",c:"Tomorrow",d:"2 days",ans:"B",exp:"一小时内。"}]],
["Student Insurance","A: Does the plan cover dental and vision?\nB: Basic covers routine cleanings/exams, not major dental or corrective lenses. Premium is more comprehensive.\nA: Cost?\nB: Basic $1200/year, Premium $2000. Monthly payments available.\nA: Can I use family insurance?\nB: Yes, with proof of comparable coverage. Waiver deadline September 15th.","A: 涵盖牙科和视力吗？\nB: 基本含常规清洁和检查，不含大型牙科或矫正镜片。高级更全面。\nA: 费用？\nB: 基本1200/年，高级2000/年。可月付。\nA: 可以用家里的保险吗？\nB: 可以，需提供相当保障的证明。免除截止9月15日。",[{q:"Basic doesn't cover?",a:"Routine cleanings",b:"Vision exams",c:"Major dental and corrective lenses",d:"Emergency visits",ans:"C",exp:"不含大型牙科和矫正镜片。"},{q:"Premium cost?",a:"$1200",b:"$1500",c:"$1800",d:"$2000",ans:"D",exp:"2000/年。"},{q:"Waiver deadline?",a:"Aug 31",b:"Sep 15",c:"Sep 30",d:"Oct 1",ans:"B",exp:"9月15日。"}]],
["Garden Volunteering","A: Interested in volunteering at the community garden.\nB: Sessions every Saturday 9-12. No experience needed.\nA: What work?\nB: Spring: planting. Summer: watering, weeding, harvesting. Fall: final crops.\nA: Do volunteers get produce?\nB: Up to 5 pounds/week. Rest goes to food banks.\nA: Minimum commitment?\nB: 2 sessions per month. Sign up online or at the garden.","A: 有兴趣做社区花园志愿者。\nB: 每周六9-12点。不需经验。\nA: 做什么？\nB: 春天播种，夏天浇水除草收获，秋天收最后作物。\nA: 能拿产品吗？\nB: 每周最多5磅。其余捐食物银行。\nA: 最低承诺？\nB: 每月2次。网上或现场报名。",[{q:"When are sessions?",a:"Sunday PM",b:"Saturday AM",c:"Wednesday PM",d:"Friday AM",ans:"B",exp:"每周六9-12。"},{q:"Produce limit?",a:"3 pounds",b:"5 pounds",c:"7 pounds",d:"Unlimited",ans:"B",exp:"每周最多5磅。"},{q:"Monthly minimum?",a:"1 session",b:"2 sessions",c:"3 sessions",d:"4 sessions",ans:"B",exp:"每月2次。"}]],
["Food Allergy","A: I have a severe peanut allergy. Safe options?\nB: Allergen-free station excludes 8 major allergens including peanuts.\nA: How to find safe food daily?\nB: Menu online with all ingredients. Allergen-free items have green tags.\nA: If I have a reaction?\nB: Staff trained with EpiPens. Emergency kits at every station.\nA: Meet the nutritionist?\nB: Dr. Patel by appointment, second floor.","A: 我有严重花生过敏。安全选择？\nB: 无过敏原餐台排除8大过敏原含花生。\nA: 每天怎么知道安全的？\nB: 菜单在线，列所有成分。无过敏原食品绿色标签。\nA: 如果过敏？\nB: 员工会用肾上腺素笔。每站有应急包。\nA: 见营养师？\nB: Patel博士可预约，二楼。",[{q:"Allergen-free station excludes?",a:"Only peanuts",b:"Nuts and dairy",c:"8 major allergens",d:"All spices",ans:"C",exp:"排除8大过敏原。"},{q:"How labeled?",a:"Red tags",b:"Blue tags",c:"Yellow tags",d:"Green tags",ans:"D",exp:"绿色标签。"},{q:"Nutritionist location?",a:"1st floor",b:"2nd floor",c:"Health center",d:"Admin",ans:"B",exp:"二楼。"}]],
["New Organization","A: I want to start a new student organization.\nB: Need 10+ students and a faculty advisor. Submit registration with constitution.\nA: We have 15 students and a professor. How long for approval?\nB: Student Government reviews monthly. Approved groups get a charter and can request funding.\nA: What funding?\nB: Up to $500 startup. After first semester, apply for annual funding.\nA: Use meeting rooms?\nB: Free for registered orgs. Book 1 week ahead online.","A: 我想创办学生组织。\nB: 需10+学生和指导老师。提交注册和章程。\nA: 我们有15人和一位教授。审批多久？\nB: 学生会月审。批准后获特许状，可申请资金。\nA: 有什么资金？\nB: 最多500启动资金。第一学期后可申请年度资金。\nA: 用会议室？\nB: 注册组织免费。提前一周在线预订。",[{q:"Students needed?",a:"5",b:"8",c:"10",d:"15",ans:"C",exp:"至少10名。"},{q:"Startup funding?",a:"$300",b:"$500",c:"$700",d:"$1000",ans:"B",exp:"最多500美元。"},{q:"Room booking advance?",a:"3 days",b:"1 week",c:"2 weeks",d:"1 month",ans:"B",exp:"提前一周。"}]],
["Homesickness","A: I've been really homesick. First time away from home.\nB: Completely normal. Many students feel this way.\nA: I miss my family and hometown.\nB: Join campus groups? Community helps. Counseling center has homesickness groups Thursday evenings.\nA: Does it get easier?\nB: Most feel at home by mid-first semester. Stay busy and make friends.","A: 我最近很想家。第一次离家。\nB: 完全正常。很多学生都这样。\nA: 想家人和家乡。\nB: 加入校园社团？社区有帮助。咨询中心每周四晚有思乡小组。\nA: 会变好吗？\nB: 大多数到第一学期中期感觉更自在。保持忙碌交朋友。",[{q:"Student experiencing?",a:"Academic stress",b:"Homesickness",c:"Financial issues",d:"Roommate problems",ans:"B",exp:"想家。"},{q:"Support group when?",a:"Monday",b:"Wednesday",c:"Thursday evening",d:"Friday",ans:"C",exp:"每周四晚。"},{q:"When feel at home?",a:"After first week",b:"Mid-first semester",c:"End of semester",d:"Second semester",ans:"B",exp:"第一学期中期。"}]],
["Package Pickup","A: Package notification—where to go?\nB: Mailroom, student center ground floor. Bring student ID.\nA: Hours?\nB: Mon-Fri 8AM-6PM, Sat 9AM-1PM. Closed Sundays.\nA: How long are packages held?\nB: 14 days before return to sender.\nA: Pick up for someone else?\nB: Need their signed authorization note.","A: 包裹通知——去哪？\nB: 学生中心一楼邮件室。带学生证。\nA: 时间？\nB: 周一至周五8-18点，周六9-13点。周日休息。\nA: 保留多久？\nB: 14天后退回发件人。\nA: 替别人取？\nB: 需签名授权书。",[{q:"Mailroom location?",a:"Dorm 1st floor",b:"Student center ground floor",c:"Library 2nd floor",d:"Admin basement",ans:"B",exp:"学生中心一楼。"},{q:"Package hold time?",a:"7 days",b:"10 days",c:"14 days",d:"21 days",ans:"C",exp:"14天。"},{q:"Pick up for others?",a:"Their ID",b:"Phone call",c:"Signed note",d:"Faculty OK",ans:"C",exp:"签名授权书。"}]],
["Online Classes","A: How to register for online courses?\nB: Same system, look for 'online' sections.\nA: Extra fees?\nB: $50 technology fee per online course.\nA: Scheduled times?\nB: Synchronous has set times. Asynchronous is self-paced with weekly deadlines.\nA: How many can I take?\nB: Undergrads: 2/semester. Grads: up to 3.\nA: I'll take one asynchronous.","A: 在线课程怎么注册？\nB: 同一系统，找'online'班。\nA: 额外费？\nB: 每门50美元技术费。\nA: 有固定时间吗？\nB: 同步有固定时间。异步自行安排但有周截止日。\nA: 可以修几门？\nB: 本科生2门/学期。研究生最多3门。\nA: 我报一门异步的。",[{q:"Tech fee?",a:"$25",b:"$30",c:"$40",d:"$50",ans:"D",exp:"50美元/门。"},{q:"Synchronous vs asynchronous?",a:"Sync is shorter",b:"Sync has set times",c:"Async costs more",d:"Async has no deadlines",ans:"B",exp:"同步有固定时间。"},{q:"Undergrad online limit?",a:"1",b:"2",c:"3",d:"Unlimited",ans:"B",exp:"最多2门。"}]],
["Guest Policy","A: My roommate invites friends without asking.\nB: Try direct conversation using 'I' statements.\nA: Like what?\nB: 'I feel uncomfortable when guests come without notice' vs 'You always invite people.'\nA: What if she doesn't change?\nB: Request mediation through Resident Advisor. Room transfers are last resort.\nA: I'll try direct talk first.","A: 室友不问就请人来。\nB: 试试用'我'的表述直接谈。\nA: 比如？\nB: '不通知就来客我不舒服'而不是'你总请人。'\nA: 她不改怎么办？\nB: 通过驻楼顾问调解。换房间是最后选择。\nA: 先试试直接谈。",[{q:"Roommate problem?",a:"Loud music",b:"Invites friends without asking",c:"Doesn't clean",d:"Stays up late",ans:"B",exp:"不问就请人来。"},{q:"Communication technique?",a:"Write a letter",b:"'I' statements",c:"Group discussion",d:"Text message",ans:"B",exp:"用'我'的表述。"},{q:"Last resort?",a:"Move out",b:"Report to housing",c:"Room transfers",d:"Family meeting",ans:"C",exp:"换房间是最后选择。"}]],
["Campus Safety","A: Any safety tips for campus?\nB: Always lock your dorm. Save campus security number—24/7.\nA: Walking alone at night?\nB: Avoid it. Use the campus escort service instead.\nA: Didn't know about that.\nB: Also sign up for campus alerts—text messages about emergencies. Register on the university website.","A: 校园安全建议？\nB: 始终锁好宿舍门。保存校园安保电话——24小时。\nA: 晚上一个人走？\nB: 尽量避免。用校园护送服务。\nA: 不知道有这个。\nB: 还要注册校园警报——紧急短信通知。大学网站注册。",[{q:"Always do what with dorm?",a:"Leave it open",b:"Keep it locked",c:"Share keys",d:"Put note on door",ans:"B",exp:"始终锁好门。"},{q:"Night walking service?",a:"Taxi",b:"Campus escort",c:"Police patrol",d:"Bike rental",ans:"B",exp:"校园护送服务。"},{q:"How to sign up for alerts?",a:"Visit security",b:"Email",c:"University website",d:"Text a code",ans:"C",exp:"大学网站注册。"}]],
["Graduate School","A: Advice for graduate school applications?\nB: Research programs matching your interests. Prepare statement of purpose, 3 recommendation letters, transcripts, and GRE scores.\nA: When to start?\nB: At least a year before target enrollment.\nA: Funding?\nB: Many doctoral programs offer full funding via assistantships. Master's less funding but scholarships available.\nA: I'll start researching this weekend.","A: 研究生申请建议？\nB: 研究匹配你兴趣的项目。准备目的陈述、3封推荐信、成绩单和GRE。\nA: 什么时候开始？\nB: 至少在入学前一年。\nA: 资金？\nB: 很多博士项目通过助教提供全额资助。硕士资助少但有奖学金。\nA: 这周末开始研究。",[{q:"What to research first?",a:"Application fees",b:"Programs matching interests",c:"Housing",d:"Nightlife",ans:"B",exp:"研究匹配兴趣的项目。"},{q:"When to start preparing?",a:"6 months before",b:"1 year before enrollment",c:"3 months before",d:"1 month before deadline",ans:"B",exp:"至少提前一年。"},{q:"Doctoral programs often offer?",a:"Free housing",b:"Full funding via assistantships",c:"Guaranteed jobs",d:"Free textbooks",ans:"B",exp:"通过助教提供全额资助。"}]],
["Research Skills","A: How to find good sources for my research paper?\nB: Start with library databases—Academic Search Complete and JSTOR for peer-reviewed articles.\nA: How to know if a source is reliable?\nB: Peer-reviewed journals, check author credentials and date. Aim for last 5-10 years.\nA: How many sources?\nB: 8-12 minimum—mix of journals, books, and reputable websites. Always cite properly.\nA: I'll start searching today.","A: 怎么找好的论文资料来源？\nB: 从图书馆数据库开始——Academic Search Complete和JSTOR找同行评审文章。\nA: 怎么判断来源可靠？\nB: 同行评审期刊，检查作者资质和日期。目标是最近5-10年。\nA: 需要多少来源？\nB: 至少8-12个——期刊、书籍和可靠网站混合。正确引用。\nA: 今天就开始搜索。",[{q:"Recommended databases?",a:"Google and Wikipedia",b:"Academic Search Complete and JSTOR",c:"Amazon and Goodreads",d:"YouTube",ans:"B",exp:"Academic Search Complete和JSTOR。"},{q:"How recent should sources be?",a:"Last year only",b:"Last 5-10 years",c:"Last 20 years",d:"Any date",ans:"B",exp:"最近5-10年。"},{q:"Minimum sources for research paper?",a:"3-5",b:"5-8",c:"8-12",d:"20+",ans:"C",exp:"至少8-12个。"}]],
["Time Management","A: Tips for balancing coursework and social life?\nB: Try Pomodoro Technique—25-minute focused blocks with 5-minute breaks.\nA: How to prioritize?\nB: Eisenhower Matrix: urgent+important, important but not urgent, urgent but not important, neither.\nA: I procrastinate on big assignments.\nB: Break large tasks into smaller steps. 'Write outline' vs 'write 10-page paper.'\nA: Dealing with distractions?\nB: Phone in another room while studying. Website blockers for social media.","A: 平衡课业和社交的建议？\nB: 试试番茄工作法——25分钟专注+5分钟休息。\nA: 如何优先排序？\nB: 艾森豪威尔矩阵：紧急+重要、重要不紧急、紧急不重要、都不。\nA: 我在大作业上拖延。\nB: 把大任务分解成小步骤。'写大纲'而不是'写10页论文'。\nA: 处理干扰？\nB: 学习时手机放另一个房间。用网站屏蔽器。",[{q:"What is Pomodoro Technique?",a:"50 min work",b:"25-min blocks with 5-min breaks",c:"Morning only",d:"Multitasking",ans:"B",exp:"25分钟专注+5分钟休息。"},{q:"Eisenhower Matrix helps with?",a:"Task difficulty",b:"Urgent and important categories",c:"Time of day scheduling",d:"Delegation",ans:"B",exp:"分为紧急和重要类别。"},{q:"Procrastination strategy?",a:"Wait until last minute",b:"Easiest first",c:"Break into smaller steps",d:"Work longer hours",ans:"C",exp:"分解成小步骤。"}]],
["Green Campus","A: What's the Green Campus Initiative?\nB: Goal: reduce carbon emissions 30% in 5 years. Solar panels, electric shuttles, comprehensive recycling.\nA: Can students participate?\nB: Yes! Green Living certification for dorms—meet sustainability criteria for housing discount.\nA: What are the criteria?\nB: Reduce energy 15%, proper recycling, participate in 2+ sustainability events per semester.\nA: I'll talk to my roommates about certifying.","A: 什么是绿色校园倡议？\nB: 目标：5年内减碳30%。太阳能板、电动班车、全面回收。\nA: 学生可以参与吗？\nB: 可以！宿舍绿色生活认证——符合可持续标准可获住房折扣。\nA: 有什么标准？\nB: 减能15%、正确回收、每学期参加2+可持续活动。\nA: 我和室友讨论认证。",[{q:"Emission reduction goal?",a:"20%",b:"30%",c:"40%",d:"50%",ans:"B",exp:"5年内减碳30%。"},{q:"Certified dorm benefit?",a:"Free meals",b:"Priority registration",c:"Housing discount",d:"Free bus",ans:"C",exp:"住房折扣。"},{q:"Energy reduction needed?",a:"5%",b:"10%",c:"15%",d:"20%",ans:"C",exp:"减能15%。"}]],
["Debate Team","A: Tell me about the debate team.\nB: We compete in intercollegiate tournaments. Practice twice weekly, Tue/Thu evenings.\nA: Need experience?\nB: Not at all. We train beginners in argumentation and public speaking.\nA: How many tournaments per year?\nB: About 8-10, including nationals in spring.\nA: Time beyond practice?\nB: 4-6 hours/week on research and case prep.\nA: How to join?\nB: Info session next Wednesday 7PM, student center.","A: 介绍辩论队。\nB: 我们参加大学锦标赛。每周二四晚上练习。\nA: 需要经验吗？\nB: 不需要。我们培训初学者。\nA: 每年几场锦标赛？\nB: 约8-10场，含春季全国赛。\nA: 练习之外的时间？\nB: 每周4-6小时研究和准备。\nA: 怎么加入？\nB: 下周三7点学生中心说明会。",[{q:"Practice frequency?",a:"Once/week",b:"Twice/week",c:"3 times/week",d:"Daily",ans:"B",exp:"每周两次。"},{q:"Tournaments per year?",a:"4-6",b:"6-8",c:"8-10",d:"12+",ans:"C",exp:"约8-10场。"},{q:"Info session when?",a:"Monday 7PM",b:"Wednesday 7PM",c:"Friday 7PM",d:"Saturday 10AM",ans:"B",exp:"下周三7点。"}]],
["Course Selection","A: I'm unsure about course selection for next semester.\nB: Start with core requirements for your major.\nA: Already signed up. What about electives?\nB: Choose ones that interest you and fulfill gen-ed requirements.\nA: How many credits as a first-year?\nB: 12-15 credits recommended. That's 4-5 courses.\nA: I'll aim for 14 credits.","A: 我不确定下学期选什么课。\nB: 从专业核心课开始。\nA: 已报了。选修课呢？\nB: 选感兴趣的且满足通识要求的。\nA: 一年级修多少学分？\nB: 建议12-15学分，约4-5门课。\nA: 我修14学分。",[{q:"First priority?",a:"Electives",b:"Core courses",c:"PE",d:"Seminars",ans:"B",exp:"先修核心课。"},{q:"Recommended credits for first-year?",a:"9-12",b:"12-15",c:"15-18",d:"18-20",ans:"B",exp:"12-15学分。"},{q:"Student's credit target?",a:"12",b:"13",c:"14",d:"15",ans:"C",exp:"14学分。"}]],
["Legal Services","A: Is there free legal help for students?\nB: Yes! Student Legal Services handles landlord-tenant, consumer, traffic, and employment issues. No criminal cases.\nA: My landlord won't fix the heating.\nB: They can review your lease and advise on tenant rights.\nA: How to make an appointment?\nB: Walk-in hours Tue/Thu 1-4PM, room 110 student services. Bring student ID, lease copy, and written communication.\nA: Thanks!","A: 有免费法律帮助吗？\nB: 有！学生法律服务处理房东-租客、消费者、交通和就业问题。不处理刑事案件。\nA: 我的房东不修暖气。\nB: 他们可以审查租约和就租客权利提供建议。\nA: 怎么预约？\nB: 周二/四1-4点临时来访，学生服务110室。带学生证、租约和书面沟通。\nA: 谢谢！",[{q:"What cases NOT handled?",a:"Landlord issues",b:"Consumer problems",c:"Criminal cases",d:"Employment",ans:"C",exp:"不处理刑事案件。"},{q:"Walk-in hours?",a:"Mon/Wed mornings",b:"Tue/Thu afternoons",c:"Wed/Fri afternoons",d:"Sat mornings",ans:"B",exp:"周二/四下午1-4点。"},{q:"What to bring?",a:"ID only",b:"ID, lease, written communication",c:"Passport",d:"License only",ans:"B",exp:"学生证、租约和书面沟通。"}]],
["Tech Repair","A: Is there a campus laptop repair service?\nB: Tech hub in IT building room 102. Software services free, hardware has service charge.\nA: My laptop keeps freezing.\nB: Back up files before bringing it in. They offer loaner laptops if repair takes more than a day.\nA: Need appointment?\nB: Walk-ins accepted, but appointments recommended during busy periods.","A: 有校园电脑维修服务吗？\nB: IT楼102室技术中心。软件服务免费，硬件有服务费。\nA: 我的笔记本总是死机。\nB: 送修前备份文件。维修超一天提供借用笔记本。\nA: 需预约吗？\nB: 接受临时来访，但忙时建议预约。",[{q:"What's free?",a:"All repairs",b:"Hardware",c:"Software services",d:"Only virus removal",ans:"C",exp:"软件服务免费。"},{q:"What if repair takes more than a day?",a:"Discount",b:"Loaner laptop",c:"Free recovery",d:"Priority service",ans:"B",exp:"提供借用笔记本。"},{q:"Before bringing in?",a:"Buy new battery",b:"Delete files",c:"Back up files",d:"Install software",ans:"C",exp:"备份文件。"}]],
["Study Room","A: Can I reserve a study room for a group?\nB: Group study rooms on 3rd and 4th floors, fit 4-8 people.\nA: How to reserve?\nB: Online system, up to 1 week in advance.\nA: Time limit?\nB: 2 hours. If available after, extend at service desk.\nA: Whiteboard provided?\nB: Yes, markers and erasers at service desk.","A: 可以预约学习室吗？\nB: 3-4楼有小组学习室，4-8人。\nA: 怎么预约？\nB: 在线系统，最多提前1周。\nA: 时间限制？\nB: 2小时。之后如果空闲可在服务台延长。\nA: 有白板吗？\nB: 有，记号笔和橡皮在服务台。",[{q:"Room capacity?",a:"2-4",b:"4-8",c:"6-10",d:"8-12",ans:"B",exp:"4-8人。"},{q:"Advance booking?",a:"3 days",b:"5 days",c:"1 week",d:"2 weeks",ans:"C",exp:"最多提前1周。"},{q:"Time limit per reservation?",a:"1 hour",b:"2 hours",c:"3 hours",d:"4 hours",ans:"B",exp:"2小时。"}]],
["Transcript Request","A: How to request a transcript?\nB: Through registrar's website, $5 each. Standard: 3-5 business days.\nA: Faster option?\nB: Expedited: additional $10, within 1 business day.\nA: Electronic transcript?\nB: Yes, same price, typically within 24 hours.\nA: Need 3 copies for grad schools.\nB: Specify multiple recipients in one request.","A: 怎么申请成绩单？\nB: 教务处网站，每份5美元。标准3-5工作日。\nA: 加急？\nB: 额外10美元，1工作日内。\nA: 电子版？\nB: 有，同价，通常24小时内。\nA: 需要3份给研究生院。\nB: 一次申请可指定多个收件人。",[{q:"Cost per transcript?",a:"$3",b:"$5",c:"$7",d:"$10",ans:"B",exp:"每份5美元。"},{q:"Expedited additional cost?",a:"$5",b:"$8",c:"$10",d:"$15",ans:"C",exp:"额外10美元。"},{q:"Electronic processing time?",a:"12 hours",b:"24 hours",c:"48 hours",d:"3 days",ans:"B",exp:"通常24小时内。"}]],
["Changing Major","A: I'm thinking about changing from engineering to computer science.\nB: Significant change. Many math/science courses will transfer.\nA: Will it delay graduation?\nB: Could add 1-2 semesters for new required courses.\nA: Scholarship impact?\nB: Some are major-specific—check terms. General aid fine if full-time maintained.\nA: How to declare?\nB: Change of major form, both department chairs' signatures, submit to registrar. Takes effect next semester.","A: 我在考虑从工程转计算机科学。\nB: 重大改变。很多数理课可以转。\nA: 会延期毕业吗？\nB: 可能增加1-2学期修新的必修课。\nA: 奖学金影响？\nB: 有些与专业绑定——查条款。一般资助保持全日制就行。\nA: 怎么申报？\nB: 专业变更表，两系主任签字，交教务处。下学期生效。",[{q:"Extra semesters possible?",a:"0",b:"1-2",c:"2-3",d:"3-4",ans:"B",exp:"可能增加1-2学期。"},{q:"Scholarship concern?",a:"All transfer",b:"Increase",c:"Some are major-specific",d:"Never affected",ans:"C",exp:"有些与专业绑定。"},{q:"When does change take effect?",a:"Immediately",b:"Next semester",c:"Next year",d:"After 1 month",ans:"B",exp:"下学期生效。"}]],
["Writing Center","A: Can the writing center help with my research paper?\nB: Absolutely! Help with any stage: brainstorming, drafting, revising.\nA: Need appointment?\nB: Recommended, but walk-ins accepted. Sessions about 30 minutes.\nA: Will they proofread?\nB: They teach strategies to improve writing—they don't proofread or edit. Bring assignment prompt and drafts.\nA: Where is it?\nB: Humanities building room 205. Book online.","A: 写作中心能帮研究论文吗？\nB: 当然！任何阶段都帮：头脑风暴、起草、修改。\nA: 要预约吗？\nB: 建议预约，也接受临时来访。约30分钟。\nA: 会校对吗？\nB: 教改善写作策略——不校对或编辑。带作业要求和草稿。\nA: 在哪？\nB: 人文学科楼205。在线预约。",[{q:"What won't they do?",a:"Brainstorm",b:"Draft",c:"Proofread or edit",d:"Revise",ans:"C",exp:"不校对或编辑。"},{q:"Session length?",a:"20 min",b:"30 min",c:"45 min",d:"60 min",ans:"B",exp:"约30分钟。"},{q:"Location?",a:"Library 105",b:"Humanities 205",c:"Science 301",d:"Student center 102",ans:"B",exp:"人文学科楼205。"}]],
["Leadership Position","A: I'd like to apply for a student leadership position.\nB: Openings for peer mentors, orientation leaders, and resident advisors.\nA: Peer mentor qualifications?\nB: Minimum GPA 3.0, 2+ semesters enrolled, strong communication skills.\nA: Time commitment?\nB: 8-10 hours/week. $1000 stipend per semester.\nA: How to apply?\nB: Application and 2 references by March 1st.","A: 我想申请学生领导职位。\nB: 有朋辈导师、新生引导员和驻楼顾问。\nA: 朋辈导师资格？\nB: GPA最低3.0，在校2+学期，良好沟通能力。\nA: 时间投入？\nB: 每周8-10小时。每学期1000美元津贴。\nA: 怎么申请？\nB: 3月1日前提交申请和2份推荐信。",[{q:"Minimum GPA?",a:"2.5",b:"2.75",c:"3.0",d:"3.5",ans:"C",exp:"最低3.0。"},{q:"Weekly hours?",a:"5-7",b:"8-10",c:"10-12",d:"12-15",ans:"B",exp:"8-10小时/周。"},{q:"Stipend per semester?",a:"$500",b:"$750",c:"$1000",d:"$1500",ans:"C",exp:"1000美元。"}]],
];

// 短文模板
const E = [
["History of the Internet","The internet began as a military project in the 1960s when the US Defense Department developed ARPANET. By the 1970s, email was invented. In 1989, Tim Berners-Lee proposed the World Wide Web. By the mid-1990s, browsers brought the internet into homes worldwide. Today, over four billion people use it daily. From social media to online shopping, the internet reshapes our society profoundly.","互联网始于1960年代的军事项目ARPANET。70年代发明了电子邮件。1989年蒂姆·伯纳斯-李提出万维网。90年代中期浏览器将互联网带入家庭。如今每天有超过40亿人使用互联网，深刻重塑我们的社会。",[{q:"What was ARPANET?",a:"A browser",b:"A military network project",c:"An email service",d:"A social platform",ans:"B",exp:"ARPANET是美国国防部开发的军事网络项目。"},{q:"Who proposed the World Wide Web?",a:"Bill Gates",b:"Steve Jobs",c:"Tim Berners-Lee",d:"Mark Zuckerberg",ans:"C",exp:"1989年蒂姆·伯纳斯-李提出万维网。"},{q:"Daily internet users today?",a:"Over 2 billion",b:"Over 3 billion",c:"Over 4 billion",d:"Over 5 billion",ans:"C",exp:"每天超过40亿人使用互联网。"}]],
["Climate Change","Rising global temperatures cause glaciers to melt at unprecedented rates, raising sea levels. Extreme weather events—hurricanes, droughts, heat waves—are more frequent. Wildlife habitats are disrupted. The Paris Climate Accord aims to limit warming to well below 2°C above pre-industrial levels. Achieving this requires cooperation from all nations and transition to renewable energy.","全球气温上升导致冰川融化加速，海平面升高。极端天气更频繁。野生动物栖息地被破坏。巴黎气候协定旨在将变暖限制在2°C以内。实现这一目标需要全球合作和可再生能源转型。",[{q:"What causes sea level rise?",a:"Deforestation",b:"Glacier melting from rising temperatures",c:"More rainfall",d:"Volcanic activity",ans:"B",exp:"气温上升导致冰川融化使海平面升高。"},{q:"Paris Accord target?",a:"1°C above pre-industrial",b:"Well below 2°C above pre-industrial",c:"3°C above pre-industrial",d:"0.5°C above pre-industrial",ans:"B",exp:"限制在2°C以内。"},{q:"What transition is needed?",a:"To nuclear energy",b:"To electric vehicles",c:"To renewable energy",d:"To organic farming",ans:"C",exp:"需要可再生能源转型。"}]],
["Benefits of Exercise","Regular exercise prevents chronic diseases—heart disease, diabetes, certain cancers. It strengthens muscles and bones, improves cardiovascular health, and boosts immunity. Exercise also benefits mental health: reducing depression and anxiety, improving mood and cognition. Studies show 30 minutes of brisk walking 5 times weekly significantly improves health. The key is finding activities you enjoy and making them routine.","规律运动预防心脏病、糖尿病和某些癌症。增强肌肉和骨骼，改善心血管和免疫力。运动还改善心理健康：减少抑郁焦虑，改善情绪和认知。研究表明每周5次30分钟快走显著改善健康。关键是找到喜欢的活动使其成为习惯。",[{q:"What diseases can exercise prevent?",a:"Only heart disease",b:"Heart disease, diabetes, and certain cancers",c:"Only diabetes",d:"All infectious diseases",ans:"B",exp:"运动可预防心脏病、糖尿病和某些癌症。"},{q:"Recommended weekly exercise?",a:"30 min × 3",b:"30 min × 5",c:"60 min × 3",d:"60 min × 5",ans:"B",exp:"每周5次30分钟。"},{q:"Key to maintaining exercise?",a:"1 hour daily",b:"Join a gym",c:"Find enjoyable activities and make them routine",d:"High-intensity only",ans:"C",exp:"找喜欢的活动使其成为习惯。"}]],
["The Water Cycle","The water cycle describes water's continuous movement. It begins with evaporation—sun heats water into vapor rising into the atmosphere. Vapor cools and condenses into clouds. When droplets grow large enough, they fall as precipitation—rain, snow, sleet, or hail. Some water flows as surface runoff back to oceans. Some infiltrates soil as groundwater. The cycle distributes fresh water and regulates global temperatures.","水循环描述水的持续运动。从蒸发开始——太阳将水加热成蒸气上升。蒸气冷却凝结成云。水滴足够大时以雨雪等形式降落。一些水作为地表径流回到海洋，一些渗入土壤成为地下水。水循环分配淡水并调节全球温度。",[{q:"Another name for water cycle?",a:"Atmospheric cycle",b:"Hydrological cycle",c:"Precipitation cycle",d:"Evaporation cycle",ans:"B",exp:"水循环也称为水文循环。"},{q:"What causes water to rise?",a:"Condensation",b:"Precipitation",c:"Evaporation",d:"Infiltration",ans:"C",exp:"蒸发使水上升。"},{q:"Why is water cycle essential?",a:"Creates oxygen",b:"Distributes fresh water and regulates temperatures",c:"Produces energy",d:"Removes pollutants",ans:"B",exp:"分配淡水并调节温度。"}]],
["Cultural Diversity","Culturally diverse cities tend to be more innovative and economically productive. Different traditions, cuisines, and perspectives benefit everyone. However, language barriers and cultural misunderstandings can create social tensions. Successful multicultural cities invest in language education and intercultural dialogue. The key is mutual respect and willingness to learn from one another.","文化多元的城市往往更具创新性和经济生产力。不同的传统、美食和观点使所有人受益。然而，语言障碍和文化误解可能造成社会紧张。成功的多元文化城市投资于语言教育和跨文化对话。关键是相互尊重和乐于学习。",[{q:"What studies show about diverse cities?",a:"More crime",b:"More innovative and productive",c:"Lower quality of life",d:"Infrastructure struggles",ans:"B",exp:"更具创新性和经济生产力。"},{q:"Challenges of diversity?",a:"Only economic",b:"Language barriers and misunderstandings",c:"Only religious",d:"Traffic",ans:"B",exp:"语言障碍和文化误解。"},{q:"Key to thriving in diversity?",a:"Assimilation",b:"Separation",c:"Mutual respect and learning",d:"Government regulation",ans:"C",exp:"相互尊重和乐于学习。"}]],
["Importance of Sleep","Adults need 7-9 hours of sleep nightly. Sleep repairs tissues, strengthens immunity, and consolidates memories. Lack of sleep impairs concentration, weakens immunity, and increases risk of obesity and heart disease. Experts recommend consistent schedules, comfortable environments, and avoiding electronic devices before bedtime. Physical activity and limiting caffeine also improve sleep quality.","成人每晚需7-9小时睡眠。睡眠修复组织、增强免疫、巩固记忆。睡眠不足损害注意力、削弱免疫、增加肥胖和心脏病风险。专家建议一致的睡眠时间表、舒适环境和睡前避免电子设备。运动和限制咖啡因也有帮助。",[{q:"How much sleep do adults need?",a:"5-7 hours",b:"7-9 hours",c:"9-11 hours",d:"6-8 hours",ans:"B",exp:"7-9小时。"},{q:"Lack of sleep leads to?",a:"Only tiredness",b:"Better memory",c:"Impaired concentration and weakened immunity",d:"Better performance",ans:"C",exp:"损害注意力和免疫力。"},{q:"Avoid before bedtime?",a:"Exercise",b:"Reading",c:"Electronic devices",d:"Water",ans:"C",exp:"睡前避免电子设备。"}]],
["AI and Jobs","AI threatens to automate many jobs—manufacturing, transportation, customer service are most vulnerable. Studies estimate up to 30% of current jobs could be automated within two decades. However, AI also creates new job types. Workers need adaptability and lifelong learning. Skills AI can't easily replicate—creativity, emotional intelligence, critical thinking—will be crucial for competitiveness.","AI威胁使许多工作自动化——制造业、交通和客服最脆弱。研究估计20年内高达30%的现有工作可能被自动化。但AI也创造新工作类型。工人需要适应性和终身学习。AI难以复制的技能——创造力、情商和批判性思维——对竞争力至关重要。",[{q:"Jobs could be automated within 2 decades?",a:"Up to 10%",b:"Up to 20%",c:"Up to 30%",d:"Up to 50%",ans:"C",exp:"高达30%。"},{q:"Most vulnerable sectors?",a:"Healthcare, education",b:"Manufacturing, transportation, customer service",c:"Government, law",d:"Arts, entertainment",ans:"B",exp:"制造业、交通和客服。"},{q:"Crucial skills for future?",a:"Programming",b:"Speed",c:"Creativity, emotional intelligence, critical thinking",d:"Math",ans:"C",exp:"创造力、情商和批判性思维。"}]],
["Power of Reading","Reading improves vocabulary, enhances cognition, and increases empathy. Fiction readers score higher on social cognition tests. Just 6 minutes of reading can reduce stress by up to 68%. For children, early reading habits correlate strongly with academic success. Parents can foster this by reading aloud and providing books. In the digital age, reading's benefits remain unchanged.","阅读改善词汇、增强认知、增加同理心。小说读者在社会认知测试中得分更高。仅6分钟阅读可减少高达68%的压力。对儿童来说，早期阅读习惯与学业成功密切相关。数字时代，阅读的好处不变。",[{q:"Stress reduction from 6 min reading?",a:"Up to 30%",b:"Up to 50%",c:"Up to 68%",d:"Up to 80%",ans:"C",exp:"高达68%。"},{q:"Fiction readers score higher on?",a:"Math tests",b:"Fitness tests",c:"Social cognition tests",d:"Language tests",ans:"C",exp:"社会认知测试。"},{q:"How can parents foster reading?",a:"Limit screen time only",b:"Read aloud and provide books",c:"Reading competitions",d:"Strict schedules",ans:"B",exp:"给孩子读书和提供书籍。"}]],
["Urbanization","Over half the world's population lives in cities, expected to reach nearly 70% by 2050. Cities offer economic opportunities, better healthcare, and education. But rapid urbanization creates housing shortages, traffic congestion, and resource pressure. Green buildings, efficient public transport, and smart city technologies are solutions for livable urban environments.","超过一半世界人口居住在城市，预计2050年达到近70%。城市提供经济机会、更好的医疗和教育。但快速城市化带来住房短缺、交通拥堵和资源压力。绿色建筑、高效公交和智慧城市技术是宜居环境的解决方案。",[{q:"Expected urban population by 2050?",a:"50%",b:"60%",c:"Nearly 70%",d:"80%",ans:"C",exp:"近70%。"},{q:"Urbanization challenge?",a:"Less population",b:"Housing shortages",c:"Lower cost of living",d:"Less traffic",ans:"B",exp:"住房短缺。"},{q:"Solutions mentioned?",a:"More roads",b:"More factories",c:"Green buildings, efficient transport, smart tech",d:"Move people to rural areas",ans:"C",exp:"绿色建筑、高效公交和智慧城市技术。"}]],
["Social Media Impact","Social media connects billions worldwide but has complex impacts. Positives: social connections, rapid emergency information, giving voice to marginalized communities. Negatives: studies link excessive use to anxiety, depression, and loneliness, especially in young people. Misinformation and online harassment are significant concerns. Finding healthy balance is key to digital well-being.","社交媒体连接了全球数十亿用户但影响复杂。积极方面：社会联系、紧急信息共享、给边缘群体发声。消极方面：研究将过度使用与焦虑、抑郁和孤独联系起来，尤其是在年轻人中。错误信息和网络骚扰是重大关切。找到健康平衡是数字健康的关键。",[{q:"Positive impact of social media?",a:"Reduces screen time",b:"Social connections and information sharing",c:"Eliminates misinformation",d:"Decreases loneliness",ans:"B",exp:"促进社会联系和信息共享。"},{q:"Negative effect of excessive use?",a:"Better health",b:"Improved sleep",c:"Anxiety and depression",d:"Higher grades",ans:"C",exp:"与焦虑和抑郁增加有关。"},{q:"What's key to digital well-being?",a:"More social media",b:"Delete all accounts",c:"Healthy balance in use",d:"Only use for work",ans:"C",exp:"找到健康平衡。"}]],
["Science of Memory","Memory involves three stages: encoding, storage, and retrieval. Short-term memory holds information for seconds to minutes; long-term memory can last a lifetime. Stress, sleep, nutrition, and age affect memory. Regular exercise, adequate sleep, and mental stimulation help maintain and improve memory function throughout life.","记忆涉及三个阶段：编码、存储和提取。短期记忆持续数秒到数分钟；长期记忆可持续一生。压力、睡眠、营养和年龄影响记忆。规律运动、充足睡眠和脑力刺激帮助维持和改善记忆功能。",[{q:"Three stages of memory?",a:"Thinking, feeling, acting",b:"Encoding, storage, retrieval",c:"Learning, practicing, testing",d:"Reading, writing, reviewing",ans:"B",exp:"编码、存储和提取。"},{q:"What affects memory?",a:"Only age",b:"Stress, sleep, nutrition, and age",c:"Only sleep",d:"Only genetics",ans:"B",exp:"压力、睡眠、营养和年龄。"},{q:"What helps maintain memory?",a:"Watching TV",b:"Large meals",c:"Exercise, sleep, mental stimulation",d:"Staying indoors",ans:"C",exp:"运动、睡眠和脑力刺激。"}]],
];

